-- W2 catalog seed batch2_herbs_berries — 20 cited profiles (generated from PlantAppPlanner scratch/catalog/profiles; sources embedded per row).
-- Upsert: already-seeded Slice-1 ids are enriched in place (version bump), never duplicated.
insert into public.plant_profiles (
  id, scientific_name, common_names, category, growth_habit, requires_support, self_fruitful, pollination_partners_required, watering_profile, feeding_profile, container_profile, light_profile, temperature_profile, seasonality, common_issues, vertical_suitability, source, version, last_reviewed_at
) values
  ('allium-schoenoprasum', 'Allium schoenoprasum', array['Chives','Common chives','Onion chives']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":6}'::jsonb, '{"baseIntervalDays":35,"postHarvestIntervalDays":35,"preferredNpk":"5-10-5"}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":8,"idealMaxLiters":15,"soilMixTags":["well-drained","rich-in-organic-matter","soil-based-compost"]}'::jsonb, '{"targetSunHours":7,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":4,"endMonth":6}],"5":[{"startMonth":4,"endMonth":6}],"6":[{"startMonth":3,"endMonth":6}],"7":[{"startMonth":3,"endMonth":5}],"8":[{"startMonth":3,"endMonth":5}]},"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Root rot can occur in wet, poorly-drained soils; ensure the container or bed drains freely (Missouri Botanical Garden).','Aphids may cluster on leaves and reduce vigor (RHS).','Leek rust (a fungal disease) shows as bright orange raised pustules on the foliage (RHS).','Avoid over-fertilizing; chives need only a very light feed (UMN Extension).','Shallow-rooted clump-former; an 8 L pot at least 20 cm deep suits container growing, larger is fine (RHS / Old Farmer''s Almanac).']::text[], 0.2, '[{"citation":"University of Minnesota Extension — Growing chives in home gardens: six to eight hours of direct light is best; tolerates light shade; water deeply so soil does not dry out around the root zone; pH 6.0-7.0; very light application of 5-10-5 fertilizer once each spring, container plants liquid-fed at half strength every four to six weeks; space plants 6 to 12 inches apart; plant after frost danger; flowers late May/June.","url":"https://extension.umn.edu/vegetables/growing-chives","field":"lightProfile"},{"citation":"University of Minnesota Extension — Growing chives: feeding guidance (light 5-10-5 once each spring; container plants liquid-fed at half strength every four to six weeks).","url":"https://extension.umn.edu/vegetables/growing-chives","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Growing chives: watering deeply to keep root zone from drying, with consistent moisture; drought tolerant but consistent watering needed for high yields.","url":"https://extension.umn.edu/vegetables/growing-chives","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Allium schoenoprasum: USDA Zones 4 to 8; height/spread 1.0-1.5 ft; full sun to part shade; medium water; bloom April-May; no serious insect or disease problems, root rot may occur in wet, poorly-drained soils; easily grown in average, medium, well-drained soils.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=j270","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Allium schoenoprasum: medium water needs and root rot risk in wet, poorly-drained soils (overwater risk).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=j270","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Allium schoenoprasum: ''No serious insect or disease problems. Root rot may occur in wet, poorly-drained soils.''","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=j270","field":"commonIssues"},{"citation":"Royal Horticultural Society — How to grow Chives: grow in sun or partial shade; containers at least 20 cm (8 in) wide and deep with peat-free soil-based compost; sow indoors early spring through summer, plant outdoors in spring; harvest late spring until die-back in autumn; space clumps at least 15 cm (6 in) apart; problems include aphids and leek rust.","url":"https://www.rhs.org.uk/herbs/chives/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society — How to grow Chives: planting/sowing in spring, harvest from late spring until die-back in autumn (seasonality); established ground plants rarely need extra water except in drought, container plants need regular moisture.","url":"https://www.rhs.org.uk/herbs/chives/grow-your-own","field":"seasonality"},{"citation":"Royal Horticultural Society — How to grow Chives: common problems are aphids (sap-sucking insects) and leek rust (fungal disease, bright orange raised pustules).","url":"https://www.rhs.org.uk/herbs/chives/grow-your-own","field":"commonIssues"},{"citation":"The Old Farmer''s Almanac — Chives: shallow root system; if planting in a pot choose one roughly 8 to 12 inches deep; grow best in full sun, tolerate light shade, grow well in partial sun (4 to 6 hours per day); harvest 3-4 times the first year, cut back monthly thereafter.","url":"https://www.almanac.com/plant/chives","field":"containerProfile"},{"citation":"Confidence note — heatStressC (30 C) is an estimate. Sources (Missouri Botanical Garden Zones 4-8, RHS, UMN) describe chives as a cold-hardy perennial that prefers cool conditions and may go semi-dormant or bolt in summer heat, but none give an explicit numeric heat-stress threshold; 30 C is a conservative onset-of-heat-stress value. coldHardyMinC (-34 C) is derived from the lower limit of USDA Zone 4 (the cold end of the Missouri Botanical Garden range) rather than a directly stated temperature.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('anethum-graveolens', 'Anethum graveolens', array['Dill','Dillweed','Dill-Oil Plant']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":8}'::jsonb, '{"baseIntervalDays":35,"preferredNpk":"5-10-5"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","loamy","organic-matter","deep-pot-for-taproot"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":0,"heatStressC":27,"frostSensitive":true}'::jsonb, '{"productiveMonths":[5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Bolts (goes to seed) quickly once temperatures rise above ~27 C (80 F); succession-sow every 2-3 weeks for continuous leaf harvest.','Powdery mildew develops when plants are overwatered or have poor air circulation; let soil dry between waterings.','Aphids cluster on stems as the plant begins to flower and seeds ripen.','Has a long taproot and transplants poorly; direct-sow and use a deep pot. Container minimum (11 L) is for a single plant in a >=25 cm / 10-12 in deep pot; larger pots reduce staking and bolting.','Tall foliage can be blown over by wind and may need staking, especially for taller (non-compact) varieties.']::text[], 0.1, '[{"citation":"University of Minnesota Extension — Growing dill in home gardens. Sun: at least 6-8 hours direct sunlight outdoors; fertilizer: 5-10-5 once in late spring, container/indoor plants liquid feed at half strength every 4-6 weeks; thin seedlings to 10-12 in; sow after spring frost danger, succession every 2-3 weeks; tender frost-sensitive annual; use a fairly deep pot with drainage.","url":"https://extension.umn.edu/vegetables/growing-dill","field":"lightProfile,feedingProfile,wateringProfile,temperatureProfile,seasonality"},{"citation":"Utah State University Extension — How to Grow Dill in Your Garden. Watering: one or two irrigations per week once established, tolerates drier soil after seed set; full sun; hardy and tolerates cold winters; hot temperatures (+95 F / ~35 C) decrease seed production; sow every 4-6 weeks; overwatering increases powdery mildew susceptibility; aphids appear as dill flowers and seeds ripen.","url":"https://extension.usu.edu/yardandgarden/research/dill-in-the-garden","field":"wateringProfile,lightProfile,temperatureProfile,commonIssues"},{"citation":"University of Wisconsin-Madison Horticulture Extension — Dill, Anethum graveolens. Does best in full sun; tolerant of light frost; bolts/flowers in hot or dry weather; thin seedlings to 3-6 in; deep pot needed for long taproot and plants may need staking; few pests besides occasional aphids or powdery mildew; host plant for black swallowtail caterpillars; germinates in 10-14 days.","url":"https://hort.extension.wisc.edu/articles/dill-anethum-graveolens/","field":"lightProfile,temperatureProfile,containerProfile,commonIssues"},{"citation":"Confidence note: No university-extension or RHS source gave an exact container volume for dill. recommendedMinLiters (11 L), idealMinLiters (19 L) and idealMaxLiters (38 L) are conservative estimates derived from the extension guidance to use a deep pot (>=25 cm / 10-12 in deep and equally wide) for the taproot for a single plant, scaling up for 2-3 plants. wateringProfile.baseIntervalDays (4) is interpolated from USU ''one or two irrigations per week'' (3.5-7 day interval) toward the more frequent end for container use; hotWeatherMultiplier and rainSkipThresholdMm are conservative care-engine estimates, not directly sourced.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('artemisia-dracunculus', 'Artemisia dracunculus', array['Tarragon','French tarragon','Estragon','Dragon sagewort']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":1.5}'::jsonb, '{"baseIntervalDays":60,"preferredNpk":"balanced, low-rate (e.g. 5-5-5); low feeder"}'::jsonb, '{"recommendedMinLiters":6,"idealMinLiters":8,"idealMaxLiters":12,"soilMixTags":["free-draining","loamy","neutral-to-slightly-alkaline","organic-matter"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":32,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":5,"endMonth":6}],"5":[{"startMonth":4,"endMonth":6}],"7":[{"startMonth":4,"endMonth":5}]},"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Root and crown rot in moist, poorly drained soils or over a wet winter; the single biggest killer. Use free-draining soil and never let the pot stay waterlogged.','French tarragon is tender in cold, wet winters and may not overwinter outdoors in damp climates; grow in a container and shelter it over winter, or apply a straw/leaf mulch in cold zones.','Loses vigour and flavour after 3-4 years; divide the clump every 3-4 years to keep it productive.','In a container the roots quickly become root-bound and flavour declines; repot or divide every 2-3 years. Container minimum (~6 L, a 20 cm / 8 in wide and deep pot per RHS) suits one plant for a season; a larger 8-12 L pot is better for a multi-year plant.','True French tarragon is sterile and cannot be grown from seed; it is only propagated from cuttings or root division. Seed sold as ''tarragon'' is usually the coarser, less flavourful Russian tarragon.','In regions where summer highs exceed about 32 C (90 F), give afternoon/partial shade to improve survival.','Foliage is toxic to dogs, cats, and horses if eaten.']::text[], 0.1, '[{"citation":"Utah State University Extension - French Tarragon in the Garden: full sun (partial shade where summer temps exceed 90 F / 32 C); water established plants once a week and let soil dry between waterings; well-drained soil, drought tolerant; low fertilizer needs, fertilize only at planting; space 24 in apart; winter hardy to zone 4; plant after last spring frost; generally insect and disease free but prone to root rot from overwatering.","url":"https://extension.usu.edu/yardandgarden/research/french-tarragon-in-the-garden","field":"wateringProfile"},{"citation":"Utah State University Extension - French Tarragon in the Garden: ''French tarragon has low fertilizer requirements'' and ''only fertilize when planting''; basis for an infrequent (~60-day) light feeding interval.","url":"https://extension.usu.edu/yardandgarden/research/french-tarragon-in-the-garden","field":"feedingProfile"},{"citation":"Utah State University Extension - French Tarragon in the Garden: winter hardy to zone 4 (cold-hardy minimum approx -29 C); partial shading recommended where summer temperatures exceed 90 F (32 C), basis for heat-stress threshold; plant after last spring frost.","url":"https://extension.usu.edu/yardandgarden/research/french-tarragon-in-the-garden","field":"temperatureProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Artemisia dracunculus: ''Full sun (6 or more hours of direct sunlight a day)''; prefers good drainage / dry conditions; drought tolerant; USDA zones 3a-8b; height 1-3 ft, width 1-1.5 ft, clumping erect herbaceous perennial; susceptible to root or crown rot in moist, poorly drained soils; toxic to dogs, cats and horses.","url":"https://plants.ces.ncsu.edu/plants/artemisia-dracunculus/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Artemisia dracunculus: USDA hardiness zones 3a-8b; clumping, erect, herbaceous perennial habit (basis for growthHabit ''upright'' and no support); foliage toxic to pets.","url":"https://plants.ces.ncsu.edu/plants/artemisia-dracunculus/","field":"growthHabit"},{"citation":"University of Illinois Extension - Tarragon (French): full sun, tolerates some light shade; soil must be well-drained, will not tolerate poorly drained soils especially over winter; divide every 3-4 years; small pots can be grown where bright light is available, kept on the dry side; true French tarragon is sterile and grown only from cuttings or division.","url":"https://extension.illinois.edu/herbs/tarragon-french","field":"commonIssues"},{"citation":"Royal Horticultural Society (RHS) - How to grow Tarragon: grow in full sun in free-draining soil or a container; for a container use one ''at least 20cm (8in) wide and deep for one plant'' with plenty of drainage holes (basis for ~6 L recommended minimum); French tarragon 50-75 cm tall, 30 cm wide; plant mid-spring to early summer; harvest shoot tips spring to autumn; French tarragon tender in wet UK winters, best containerised and sheltered over winter; avoid overwatering as it dislikes damp.","url":"https://www.rhs.org.uk/herbs/tarragon/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS) - How to grow Tarragon: harvest from spring to autumn taking young shoot tips; plant mid-spring to early summer; winter dormancy (basis for productiveMonths / plantingWindows / dormancyMonths).","url":"https://www.rhs.org.uk/herbs/tarragon/grow-your-own","field":"seasonality"},{"citation":"Confidence note: feedingProfile.baseIntervalDays (60) is estimated. Extension sources (USU) state tarragon is a low feeder needing fertiliser essentially only at planting, and RHS gives no feeding schedule, so no source specifies an exact recurring interval; 60 days is a conservative low-rate interval consistent with ''low fertilizer requirements''. hotWeatherMultiplier (1.5) is also an estimate - sources confirm increased water need in hot/dry spells and the once-weekly baseline but give no explicit multiplier.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('coriandrum-sativum', 'Coriandrum sativum', array['Cilantro','Coriander','Chinese parsley']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":8}'::jsonb, '{"baseIntervalDays":21,"preferredNpk":"balanced low-nitrogen (light feeding)"}'::jsonb, '{"recommendedMinLiters":5,"idealMinLiters":8,"idealMaxLiters":15,"soilMixTags":["free-draining","multi-purpose-compost","ph-6-7","rich-in-organic-matter"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":0,"heatStressC":27,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"default":[{"startMonth":3,"endMonth":5},{"startMonth":9,"endMonth":10}]},"productiveMonths":[4,5,6,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Bolting (premature flowering) in summer heat and long days; provide light afternoon shade and consistent moisture to delay it. Sources confirm bolting is triggered by heat and by irregular watering / dry soil.','Sensitive to both frost and heat; not cold hardy below freezing and prone to stress in hot weather. Protect from frost and avoid midday sun in hot climates.','Containers dry out faster than the ground (RHS): check daily in warm weather and keep compost just moist without waterlogging.','Avoid over-fertilizing; only light nitrogen feeding is needed (Clemson).','Sow successively every 1-3 weeks for a continuous leaf supply, as individual plants are short-lived.']::text[], 0.2, '[{"citation":"Clemson Cooperative Extension HGIC - The Cilantro-Coriander Connection: at least six hours of sun per day; soil pH 6-7 with 20-25% organic matter, well-drained; about an inch of water a week once established; spacing 6-8 in apart; light nitrogen fertilizer, avoid over-fertilizing; bolts as temperatures rise late in the season.","url":"https://hgic.clemson.edu/the-cilantro-coriander-connection/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC - The Cilantro-Coriander Connection: about an inch of water a week once established unless extremely hot; well-drained soil; bolts when temperatures rise.","url":"https://hgic.clemson.edu/the-cilantro-coriander-connection/","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension HGIC - The Cilantro-Coriander Connection: light applications of a nitrogen fertilizer keep plants lush; avoid the tendency to over-fertilize. Soil pH 6-7 with 20-25% organic matter, well-drained.","url":"https://hgic.clemson.edu/the-cilantro-coriander-connection/","field":"feedingProfile"},{"citation":"RHS - How to grow Coriander: thrives in a sunny or lightly shaded spot; for summer leaf harvests use cooler/midday-shaded positions to prevent early flowering (bolting); performs particularly well in containers due to free-draining preference; container plants dry faster - check daily and keep compost just moist without waterlogging; space ~10cm (4in) apart; bolts in hot, dry weather; harvest leaves at 10-15cm (4-6in); seeds ~10+ weeks from sowing.","url":"https://www.rhs.org.uk/herbs/coriander/grow-your-own","field":"containerProfile"},{"citation":"RHS - How to grow Coriander: container-grown coriander should be checked daily and watered to keep compost just moist; ground-grown needs minimal watering except in extended dry periods; bolts in hot, dry weather, regular watering delays flowering.","url":"https://www.rhs.org.uk/herbs/coriander/grow-your-own","field":"wateringProfile"},{"citation":"UC Master Gardener Program of Sonoma County - Cilantro and Coriander: prefers full sun except in hot microclimates where light shade is preferred; water soil regularly because irregular watering and dry soil cause bolting; cilantro is neither frost- nor heat-tolerant; spring planting from about May 1, succession sow every 1-3 weeks; thin to 3-4 in apart; small crops thrive in containers; fall planting needs at least 60 days for leafy growth before first frost.","url":"https://ucanr.edu/sites/scmg/Food_Gardening/Feature_Vegetables/Coriander/","field":"lightProfile"},{"citation":"UC Master Gardener Program of Sonoma County - Cilantro and Coriander: cilantro is neither frost- nor heat-tolerant; plant in spring after last frost and again in fall; succession sow every 1-3 weeks.","url":"https://ucanr.edu/sites/scmg/Food_Gardening/Feature_Vegetables/Coriander/","field":"seasonality"},{"citation":"Missouri Botanical Garden Plant Finder - Coriandrum sativum: full sun to part shade, light afternoon shade helps avoid sun scald in hot summer climates; medium water needs in well-drained soils; USDA zones 2-11; mature height 1.5-2 ft; leaf pinching can begin in 30 days, seeds ready in 90 days; plants bolt easily in hot summer climates.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=275984&isprofile=1&basic=Parsley","field":"temperatureProfile"},{"citation":"The Old Farmer''s Almanac - Coriander and Cilantro: plant in spring after the last frost date or in fall; not cold hardy and requires protection from frost; plants prefer at least 6 hours of sun, but for leaf production partial shade is more productive; plants bolt in summer heat; sow a new patch every 2-3 weeks for continuous supply.","url":"https://www.almanac.com/plant/cilantro-coriander","field":"seasonality"},{"citation":"Confidence note: Exact coldHardyMinC and heatStressC are not published as numeric thresholds by the cited extension/RHS/Almanac sources. Sources uniformly state cilantro is frost-sensitive (not cold hardy) and bolts in summer heat. coldHardyMinC set to 0C (freezing) as a conservative protect-from-frost floor; heatStressC set to 27C (~80F) as a conservative bolting-onset estimate consistent with ''bolts as temperatures rise in summer''. Treat both as estimates.","url":"https://www.almanac.com/plant/cilantro-coriander","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('foeniculum-vulgare', 'Foeniculum vulgare', array['Fennel','Common fennel','Sweet fennel','Florence fennel']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.7,"preferredNpk":"balanced (e.g. 10-10-10), light feeder"}'::jsonb, '{"recommendedMinLiters":20,"idealMinLiters":25,"idealMaxLiters":40,"soilMixTags":["free-draining","rich-in-organic-matter","multi-purpose-compost","neutral-pH"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"4-9":[{"startMonth":4,"endMonth":7}]},"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Stem and root rot in poorly-drained or waterlogged soil; let the top inch dry between waterings and use free-draining mix.','Bolting (premature flowering) if moisture is uneven or the plant is heat-stressed; keep soil consistently moist during bulb development.','Aphids on fresh spring foliage; usually minor.','Slugs and snails damage young seedlings.','Swallowtail butterfly caterpillars may feed on the foliage.','Has a taproot and resents transplanting/root disturbance; sow direct or transplant young to avoid transplant shock.','Container minimum (about 20 L, ~30 cm wide and deep per RHS) suits Florence/bulb and herb fennel; the plant grows tall (1.2-1.8 m), so use a heavy, stable, sheltered pot to prevent it blowing over.','Self-seeds aggressively; deadhead spent flowers to control spread.']::text[], 0.1, '[{"citation":"Missouri Botanical Garden Plant Finder - Foeniculum vulgare: Zone 4 to 9, Sun = Full sun, Water = Medium, height 4-6 ft, problems include stem/root rot, aphids, slugs.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=275990","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Foeniculum vulgare: USDA hardiness Zone 4 (approx. -34 C cold limit) to 9; full sun; medium water needs.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=275990","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Foeniculum vulgare: common problems are stem and root rot (especially in poorly-drained conditions), aphids, slugs, and swallowtail butterfly caterpillars.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=275990","field":"commonIssues"},{"citation":"RHS - How to grow Fennel: grow in a large container at least 30 cm (1 ft) wide and deep filled with peat-free multi-purpose compost; use a heavy, stable, sheltered pot as fennel grows tall and can blow over.","url":"https://www.rhs.org.uk/herbs/fennel/grow-your-own","field":"containerProfile"},{"citation":"RHS - How to grow Fennel: needs no feeding and is drought-tolerant once established; container plants need a steady supply of moisture through the growing season; full sun, warm, sheltered, free-draining soil.","url":"https://www.rhs.org.uk/herbs/fennel/grow-your-own","field":"feedingProfile"},{"citation":"RHS - How to grow Fennel: free-draining soil essential; avoid waterlogged conditions (root rot risk); container plants need steady moisture but herb fennel is hardy and drought-tolerant once established.","url":"https://www.rhs.org.uk/herbs/fennel/grow-your-own","field":"wateringProfile"},{"citation":"The Old Farmer''s Almanac - Fennel: likes an inch of water per week or more but is drought tolerant once established (taproot); full sun; fertile soil high in organic matter; neutral pH 6.5-7.5; thin to 6-9 in spacing; constantly damp foliage invites fungal issues.","url":"https://www.almanac.com/plant/fennel","field":"wateringProfile"},{"citation":"The Old Farmer''s Almanac - Fennel: forms a taproot and can suffer extreme transplant shock if the taproot is injured; sow direct in midsummer; full-sun herb-garden/flower-bed crop.","url":"https://www.almanac.com/plant/fennel","field":"commonIssues"},{"citation":"University of Illinois Extension - Fennel: herb fennel sown in spring after frost is past; Florence fennel sown mid-June to July for cooler-season bulb development; prefers full sun and uniformly moist soil.","url":"https://extension.illinois.edu/herbs/fennel","field":"seasonality"},{"citation":"Confidence note: targetSunHours (7) and hotWeatherMultiplier (1.5) are conservative estimates derived from qualitative ''full sun'' guidance (Missouri Bot. Garden, RHS, Almanac) standardized to the common 6-8 h/day full-sun convention; no source gave an exact hours/day figure. Feeding interval (30 days) is a conservative light-feeder estimate since RHS states fennel ''needs no feeding'' while the Almanac calls it a heavy feeder in poor soil - intervals span widely by context. baseIntervalDays (4) is derived from the Almanac ''1 inch/week'' guideline interpreted for container drying.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('fragaria-x-ananassa', 'Fragaria x ananassa', array['Strawberry','Garden strawberry']::text[], 'berry', 'rosette', false, true, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"high","hotWeatherMultiplier":1.5}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":21,"preferredNpk":"high-potassium"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":8,"idealMaxLiters":19,"soilMixTags":["loam","well-draining","organic-rich"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-6,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"us-southeast":[{"startMonth":9,"endMonth":11}],"us-temperate":[{"startMonth":3,"endMonth":5}],"uk":[{"startMonth":8,"endMonth":9}]},"productiveMonths":[4,5,6,7,8],"dormancyMonths":[12,1,2]}'::jsonb, array['Botrytis (grey mould) on fruit and crown, worsened by overhead watering or soggy soil; water at the base in the morning and avoid wetting the crown','Shallow roots dry out fast, especially in containers, so containers need frequent watering','Frost during flowering blackens and kills open blooms even though dormant plants are hardy; cover with row cover or cloche when frost threatens flowers','Birds, slugs, snails, aphids, spotted wing drosophila and vine weevil; anthracnose, verticillium wilt and viruses','Below roughly -6 C (20 F) plants go dormant and benefit from a ~4 inch straw mulch for winter protection']::text[], 0.7, '[{"citation":"Clemson Cooperative Extension Home & Garden Information Center, Growing Strawberries (HGIC 1404): full sun; 1 to 1.5 inches of water per week wetting soil 6 to 8 inches deep; soil pH 6.0 to 6.5; annual hill spacing 12 inches; nitrogen side-dress about one month after planting and post-renovation feeding mid-August to mid-September; harvest March to May by region; problems anthracnose, Botrytis (gray mold), nematodes, birds.","url":"https://hgic.clemson.edu/factsheet/growing-strawberries/","field":"wateringProfile,lightProfile,feedingProfile,seasonality,commonIssues"},{"citation":"Royal Horticultural Society, How to grow strawberries: full sun for sweetest fruit (tolerates some shade); avoid wetting the crown and water in the morning to prevent grey mould; containers dry out quickly and need regular watering; feed container plants fortnightly with a general-purpose then high-potassium liquid feed once flower buds form; plant spring, late summer or early autumn (Aug/Sep best); summer-fruiting crop early June to early August; hardy but cover flowers/early fruit if frost forecast; problems include grey mould, aphids, slugs/snails, spotted wing drosophila, vine weevil, verticillium wilt and viruses.","url":"https://www.rhs.org.uk/fruit/strawberries/grow-your-own","field":"lightProfile,wateringProfile,feedingProfile,seasonality,commonIssues,temperatureProfile"},{"citation":"The Old Farmer''s Almanac, How to Grow Strawberries: requires 6 to 10 hours of direct sunlight a day; day-neutral types fruit while temperatures stay between 35 and 85 F (1 to 30 C); super-hardy but frost turns flowers to blackened mush; plants go dormant when temperatures regularly drop into the low twenties F, cut foliage to ~1 inch when air reaches 20 F (-6 C) and mulch ~4 inches deep for winter protection.","url":"https://www.almanac.com/plant/strawberries","field":"lightProfile,temperatureProfile,seasonality,commonIssues"},{"citation":"EarthBox, Growing Strawberries in Containers: a single strawberry plant needs a pot at least 8 to 10 inches deep and roughly 12 to 18 inches wide; a 6 to 8 inch pot holds 1 plant, a 10 to 12 inch pot 2 to 3 plants, and a 5-gallon (~19 L) grow bag about 3 plants. Used to bound container minimum (~4 L single small pot), ideal min ~8 L, and ideal max ~19 L.","url":"https://earthbox.com/blog/growing-strawberries-in-containers","field":"containerProfile"},{"citation":"Confidence note: container liters are converted from inch/gallon pot guidance (no extension source states liters directly); recommendedMinLiters=4 retains the proven seed value and reflects a single-plant ~1-gallon small pot, with idealMin/Max (8-19 L) bracketing multi-plant pots. coldHardyMinC=-6 C is set to the Almanac''s 20 F foliage/dormancy threshold as a conservative active-growth floor rather than the deeper temperature dormant crowns can survive under mulch. verticalSuitability=0.7 reflects strawberries'' well-documented suitability for towers/hanging baskets but is an interpretive score, not a sourced number. hotWeatherMultiplier=1.5 is an engine estimate for shallow-rooted, low-drying-tolerance plants, not a published figure.","field":"confidence"}]'::jsonb, 2, '2026-06-02'),
  ('lavandula-angustifolia', 'Lavandula angustifolia', array['English lavender','Common lavender','True lavender','Narrow-leaved lavender','Lavender']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":60,"containerLeachAdjustment":0.75,"preferredNpk":"low-nitrogen / minimal feeding"}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":10,"idealMaxLiters":18,"soilMixTags":["free-draining","low-fertility","alkaline","loam-based-john-innes-no2","added-coarse-grit","gritty-sandy"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-23,"heatStressC":38,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"6":[{"startMonth":4,"endMonth":6}],"7":[{"startMonth":4,"endMonth":5}],"8":[{"startMonth":4,"endMonth":5}]},"productiveMonths":[6,7,8],"dormancyMonths":[12,1,2]}'::jsonb, array['Root rot from overwatering or wet/heavy clay soils is the most common killer; ensure sharp drainage and let soil dry between waterings.','Leaf spot fungal disease in humid, crowded conditions; provide good air circulation.','Declines or is short-lived in hot, humid summers (e.g. USDA zone 8 and warmer humid regions).','In containers the root zone is less cold-hardy than in the ground; in zone 5/6 move pots to a sheltered spot or insulate over winter.','Container minimum of ~8 L reflects a young/dwarf plant; a mature English lavender is better in a 10-18 L (30-40 cm diameter) pot for vigor and winter root insulation.','Wait to plant until spring frost danger passes and soil reaches about 15 C (60 F).']::text[], 0.1, '[{"citation":"The Old Farmer''s Almanac - Lavender: How to Plant, Grow, and Care for Lavender Flowers. States full sun at least 6 to 8 hours/day; hardy in Zones 5 and warmer; plant in spring after soil warms to at least 60 F (15 C) and frost danger passes; must drain well, overwatering rots roots, thrives in semiarid conditions.","url":"https://www.almanac.com/plant/lavender","field":"lightProfile"},{"citation":"The Old Farmer''s Almanac - Lavender. Hardy in Zones 5 and warmer, overwinters in ground without protection; wait until top inch of soil is dry before watering; modest water needs after establishment; spring planting after soil >= 60 F (15 C).","url":"https://www.almanac.com/plant/lavender","field":"wateringProfile"},{"citation":"The Old Farmer''s Almanac - Lavender. Spring planting (after soil warms to ~60 F / 15 C and frost passes); hardy Zone 5+.","url":"https://www.almanac.com/plant/lavender","field":"seasonality"},{"citation":"Missouri Botanical Garden Plant Finder - Lavandula angustifolia ''Munstead''. USDA zone 5 to 8; full sun; water needs ''dry to medium''; average, dry to medium, well-drained, alkaline soil, light sandy soil with low fertility; height/spread 1.0-1.5 ft; bloom June-August; susceptible to leaf spot and root rot; may not survive winter if soils are not well-drained or temperatures dip below zero degrees F (-17.8 C) without snow cover.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=249422&isprofile=0&basic=munstead","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Lavandula angustifolia ''Munstead''. Water needs ''dry to medium''; susceptible to root rot in poorly drained conditions especially in winter.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=249422&isprofile=0&basic=munstead","field":"commonIssues"},{"citation":"RHS Growing Guide - How to grow lavender. English types usually hardy and left outside over winter in free-draining soil; in containers water regularly in summer (about once or twice a week in hot weather), keep fairly dry in winter; in the ground rarely needs watering after establishment; containers 30-40 cm diameter; peat-free loam-based compost such as John Innes No.2 plus up to 25% coarse grit; plants don''t generally need feeding; plant in April or May, never in winter; full sun.","url":"https://www.rhs.org.uk/plants/lavender/growing-guide","field":"containerProfile"},{"citation":"RHS Growing Guide - How to grow lavender. Plants don''t generally need feeding; container plants benefit from minimal/occasional feeding only.","url":"https://www.rhs.org.uk/plants/lavender/growing-guide","field":"feedingProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Lavandula angustifolia. USDA hardiness 5a-9b; full sun (6+ hours direct sun) or partial; low water needs, drought tolerant, does not like wet feet and dies in heavy clays; neutral to alkaline pH 6.0-8.0+; evergreen perennial shrub, broadly mounded, 1-2 ft tall x 2-3 ft wide; low maintenance; problems include root rot from overwatering and leaf spot fungal disease (good air circulation helps).","url":"https://plants.ces.ncsu.edu/plants/lavandula-angustifolia/","field":"temperatureProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Lavandula angustifolia. Evergreen perennial shrub, broadly mounded woody habit; low water; root rot and leaf spot are the common problems.","url":"https://plants.ces.ncsu.edu/plants/lavandula-angustifolia/","field":"growthHabit"},{"citation":"Confidence note: coldHardyMinC set to -23 C as a conservative value. Sources agree on USDA zone 5 hardiness (zone 5a low ~ -28.9 C; zone 5b low ~ -26.1 C), but Missouri Botanical Garden warns plants may not survive below 0 F (-17.8 C) without snow cover and that container roots are less hardy than ground roots. -23 C is a middle, conservative ground-hardiness figure rather than the absolute zone-5a extreme.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=249422&isprofile=0&basic=munstead","field":"confidence"},{"citation":"Confidence note: heatStressC set to 38 C. Extension sources (Utah State, others) indicate English lavender performs best below ~105 F (40.6 C) and declines in hot, humid zone 8 summers; 38 C is a conservative onset-of-heat-stress estimate, as no single extension page gave an exact heat-stress threshold in Celsius.","url":"https://extension.usu.edu/yardandgarden/research/english-lavender-in-the-garden","field":"confidence"},{"citation":"Confidence note: wateringProfile baseIntervalDays of 7 reflects RHS container guidance (water about once or twice weekly in hot summer weather, much less otherwise). In-ground established plants need far less water; 7 days is a conservative container-oriented default for an app, with high dryingTolerance and high overwaterRisk encoding lavender''s drought preference and root-rot risk.","url":"https://www.rhs.org.uk/plants/lavender/growing-guide","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('melissa-officinalis', 'Melissa officinalis', array['Lemon balm','Balm','Sweet balm','Common balm']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.5,"preferredNpk":"balanced low-strength (e.g. 5-5-5); herbs need low fertility for best leaf flavor"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":12,"idealMaxLiters":20,"soilMixTags":["well-drained","soil-based-compost","fertile","moisture-retentive"]}'::jsonb, '{"targetSunHours":6,"minSunHours":3,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"3-9":[{"startMonth":4,"endMonth":6}]},"productiveMonths":[5,6,7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Powdery mildew in humid or crowded conditions; cut affected stems back hard to stimulate fresh growth (RHS, Wisconsin Extension).','Susceptible to root rot if overwatered or left in waterlogged soil, especially over cold wet winters (Old Farmer''s Almanac, RHS).','Spreads aggressively by self-seeding and runners; grow in a container to curtail spread and deadhead after flowering (RHS, Wisconsin Extension).','Occasional leaf spot, gray mold, and leafhoppers (Missouri Botanical Garden, RHS).','Container plants benefit from a sheltered spot over winter out of excessive rain (RHS).']::text[], 0.2, '[{"citation":"University of Wisconsin-Madison Division of Extension - Wisconsin Horticulture: Lemon Balm, Melissa officinalis. Full sun in fertile well-drained soil; hardy zones 3a-9b; plants ~2 ft tall; space 16-18 in apart; few pest/disease problems, occasional powdery mildew; sow indoors 4-6 weeks before last frost.","url":"https://hort.extension.wisc.edu/articles/lemon-balm-melissa-officinalis/","field":"lightProfile"},{"citation":"University of Wisconsin-Madison Division of Extension - Wisconsin Horticulture: Lemon Balm. Hardy zones 3a to 9b (perennial); planting/start timing and spacing.","url":"https://hort.extension.wisc.edu/articles/lemon-balm-melissa-officinalis/","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder: Melissa officinalis. Full sun to part shade; dry to medium well-drained soils, avoid wet/winter moisture; USDA zones 3-7 (Plant Finder); height 1.5-2 ft, spread 1.5-3 ft; low maintenance; occasional powdery mildew, leaf spot, gray mold; bloom June-August.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=c857","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder: Melissa officinalis. Light = full sun to part shade, afternoon shade beneficial in hot climates; bloom June-August informs productive months.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=c857","field":"seasonality"},{"citation":"Royal Horticultural Society (RHS): How to grow Lemon balm. Sun or partial shade; container plants kept evenly moist while established garden plants are drought-tolerant; grow in large pots at least 25cm (10in) wide and deep in peat-free soil-based compost; tolerates most soils but avoid waterlogging; powdery mildew and leafhoppers occasional; container plants moved to shelter over winter.","url":"https://www.rhs.org.uk/herbs/lemon-balm/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS): How to grow Lemon balm. Container plants need regular moisture to keep compost evenly moist; established garden plants are drought-tolerant - informs medium drying tolerance and overwatering/root-rot caution.","url":"https://www.rhs.org.uk/herbs/lemon-balm/grow-your-own","field":"wateringProfile"},{"citation":"The Old Farmer''s Almanac: Lemon Balm Planting, Growing, and Harvesting Guide. Avoid overwatering - lemon balm is sensitive to root rot; needs moist (not oversaturated) soil; works well in a small pot or patio planter; herbs generally do not need highly fertile soil (very fertile soil reduces leaf flavor); space transplants ~18 in apart.","url":"https://www.almanac.com/plant/lemon-balm","field":"feedingProfile"},{"citation":"Confidence note: No authoritative source gives an exact watering interval (days), feeding interval (days), or pot volume in liters for lemon balm. baseIntervalDays=3 and overwaterRisk=high are derived conservatively from RHS ''keep compost evenly moist'' for containers combined with Almanac/MoBot root-rot and dry-to-medium guidance. feedingProfile.baseIntervalDays=30 is a conservative herb default consistent with Almanac''s ''herbs do not need highly fertile soil.'' containerProfile liters are converted from RHS ''at least 25cm (10in) wide and deep'' (a ~25cm pot approximates 11-12 L); idealMax estimated. hotWeatherMultiplier, rainSkipThresholdMm, coldHardyMinC (zone 3 lower bound ~ -34C) and heatStressC (~30C, afternoon-shade benefit) are reasonable estimates, not directly stated.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('mentha-spicata', 'Mentha spicata', array['Spearmint','Mint','Garden mint','Common mint']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"low","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":28,"postHarvestIntervalDays":28,"containerLeachAdjustment":0.75,"preferredNpk":"balanced (e.g. 10-10-10)"}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":19,"idealMaxLiters":30,"soilMixTags":["rich","moisture-retentive","well-drained","loamy"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-20,"heatStressC":32,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"7":[{"startMonth":4,"endMonth":5}],"9":[{"startMonth":3,"endMonth":5}]},"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Aggressive spreader: spreads by underground rhizomes and surface runners and can become invasive. Always grow in a contained pot or with a root barrier (Missouri Botanical Garden; UC ANR).','Mints grow better in wide-mouthed containers than deep ones; use a pot at least 15 cm (6 in) deep with a large surface area, or a ~19 L (5-gallon) container with added drainage holes (UC ANR).','Keep soil consistently moist; small containers dry out quickly in hot weather and may need water more than once a day. Spearmint tolerates wet soil but should not be left bone dry (UC ANR; Missouri Botanical Garden).','Deciduous: top growth dies back in winter and regrows from the crown/rhizomes in spring (RHS).','Frequent harvesting and pruning keep plants bushy and flavorful; flowers (lilac/pink/white) appear July-August and shoots can be sheared back after flowering (Old Farmer''s Almanac; Missouri Botanical Garden).']::text[], 0.2, '[{"citation":"RHS - Mentha spicata (spearmint), plant details: full sun or partial shade; moist but well-drained soil; hardiness H7 (hardy below -20C); deciduous; ultimate height 0.5-1 m, spread 1-1.5 m.","url":"https://www.rhs.org.uk/plants/11055/mentha-spicata/details","field":"temperatureProfile"},{"citation":"RHS - Mentha spicata: position full sun or partial shade; deciduous oval bright-green leaves; water newly planted specimens until established and provide summer irrigation for container-grown plants.","url":"https://www.rhs.org.uk/plants/11055/mentha-spicata/details","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Mentha spicata ''Kentucky Colonel'': USDA zones 5-9; full sun to part shade; water medium to wet, thrives in rich moist soils and tolerates wet conditions; 1-2 ft tall and wide; rhizomatous perennial; blooms July-August; no serious pests/diseases but an aggressive spreader.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a244","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Mentha spicata: hardiness zones 5-9; mature size 1-2 ft; growth habit rhizomatous, spreads to form ground cover; bloom time July-August.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a244","field":"seasonality"},{"citation":"UC ANR (UC Cooperative Extension, Fresno) - ''So you want to grow mint!'': full sun to part shade; moderate water, water when soil becomes dry in hot weather and note small containers dry out faster; use containers at least 6 inches deep, five-gallon buckets work well with added drainage; avoid terra cotta; mint spreads rapidly without a physical barrier.","url":"https://ucanr.edu/blog/fresno-gardening-green/article/so-you-want-grow-mint","field":"containerProfile"},{"citation":"Old Farmer''s Almanac - Mint: Planting, Growing, and Harvesting: grow in pots to prevent spreading; keep soil evenly moist; minimal care, benefits from frequent picking and pruning; spreads by horizontal runners and underground rhizomes.","url":"https://www.almanac.com/plant/mint","field":"wateringProfile"},{"citation":"Confidence note: feedingProfile intervals (28-day light feeding, balanced NPK, container-leach adjustment) are a conservative estimate. Authoritative extension/RHS sources for spearmint emphasize rich, moist soil and minimal care but do not specify a numeric fertilizer interval; mint is a low-feed herb and over-fertilizing reduces essential-oil/flavor concentration. The targetSunHours value (6) is interpolated from ''full sun to part shade'' guidance plus the widely cited 5-6 hours for best color/flavor; minSunHours/maxSunHours and heatStressC (32C) are conservative estimates not given as explicit numbers by the cited sources.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('ocimum-basilicum', 'Ocimum basilicum', array['Basil','Sweet basil','Genovese basil']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":1.5,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":15}'::jsonb, '{"baseIntervalDays":14,"preferredNpk":"balanced organic-based liquid feed (e.g. 5-10-5 or balanced all-purpose) at half strength for indoor containers; AVOID potassium-rich/tomato feed, which encourages flowering and reduces leaf flavour"}'::jsonb, '{"recommendedMinLiters":3,"idealMinLiters":6,"idealMaxLiters":10,"soilMixTags":["well-drained","soilless-potting-mix","organic-matter-rich"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7,8,9]}'::jsonb, array['Tender annual — killed by frost; foliage blackens and growth stunts at cold temperatures around 10C (50F). Do not plant out until nights stay above 10C.','Hates wet roots overnight: water at the base in the morning, keep foliage dry, and never let it sit waterlogged (overwatering / poor drainage causes root rot and damping off).','Basil downy mildew — fluffy grey-purple growth on leaf undersides; favoured by wet leaves and humidity. Water at soil level and space plants for airflow.','Fusarium wilt and grey mould (Botrytis) in damp, crowded conditions.','Aphids, leafhoppers, and slugs/snails on soft new growth.','Flowering reduces leaf flavour — pinch/harvest tips regularly and remove flower buds to keep plants leafy.','Container plants dry out and run short of nutrients faster than ground-grown plants; a small (~3 L) pot needs frequent watering, so a 6-10 L (20 cm / 8 in wide and deep) pot is easier to keep evenly moist.']::text[], 0.3, '[{"citation":"UMN Extension - Growing basil in home gardens. Needs at least 6-8 hours of bright light/day; water deeply every 7-10 days in beds, containers dry out faster and need more frequent watering; tender annual sown after danger of spring frost passes; cold soil/air stunts growth and can blacken leaves around 50F (10C), really leafs out once temps reach 80F; space 6-12 in apart; 5-10-5 fertiliser once or twice per season (indoor containers: liquid feed at half strength every 4-6 weeks; outdoor containers every 3-4 weeks); seeds germinate in 5-7 days; harvest by pinching just above a leaf pair to encourage branching; basil downy mildew is the main problem.","url":"https://extension.umn.edu/vegetables/growing-basil","field":"lightProfile,wateringProfile,temperatureProfile,feedingProfile,seasonality,commonIssues"},{"citation":"RHS - How to grow basil. Seeds germinate well at about 20C (68F); only plant out in early summer once night temperatures stay above 10C; final container at least 20cm (8in) wide and deep; water to keep compost evenly moist but avoid splashing leaves and water in the morning as basil hates having wet roots overnight; for container plants apply a balanced organic-based liquid feed and AVOID potassium-rich/tomato feed (encourages flowering); warm, sunny, sheltered position; problems include aphids, damping off, grey mould, powdery/downy mildews, leafhoppers and slugs/snails.","url":"https://www.rhs.org.uk/herbs/basil/grow-your-own","field":"temperatureProfile,containerProfile,wateringProfile,feedingProfile,lightProfile,commonIssues"},{"citation":"Clemson HGIC - Herbs. Almost all herbs (incl. basil) grow best in a site sunny at least 6 hours/day; water thoroughly then allow soil to dry out somewhat before watering again; basil is a tender annual sown after all danger of frost is past and is killed by frost; most herbs do not need highly fertile soil (excess fertility reduces flavour); harvest leaves frequently to prevent flowering, which reduces flavour; aphids common in crowded, succulent growth.","url":"https://hgic.clemson.edu/factsheet/herbs/","field":"lightProfile,wateringProfile,temperatureProfile,feedingProfile,commonIssues"},{"citation":"Confidence note - several values are conservative interpretations rather than directly stated numbers. wateringProfile.baseIntervalDays (1.5, carried from the v1 seed) reflects a small container that dries fast and basil''s low drying tolerance; UMN''s ''7-10 days'' applies to in-ground beds, not pots. hotWeatherMultiplier (1.5) and rainSkipThresholdMm (15) are estimates consistent with ''water more often in hot weather''. containerProfile.recommendedMinLiters (3, from seed) is a usable small-pot minimum; idealMin/Max (6-10 L) derive from RHS''s 20cm/8in final container. temperatureProfile.heatStressC (35) is conservative - basil is heat-loving and sources cite no firm upper damage threshold (it ''really leafs out'' at ~27C/80F), so this is a low-confidence upper bound. lightProfile.targetSunHours (7) is the midpoint of the cited 6-8 hour range.","field":"confidence"}]'::jsonb, 2, '2026-06-02'),
  ('origanum-vulgare', 'Origanum vulgare', array['Oregano','Common oregano','Wild marjoram','Greek oregano']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"balanced general-purpose"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":8,"soilMixTags":["free-draining","soil-based-compost","horticultural-grit","low-fertility"]}'::jsonb, '{"targetSunHours":6,"minSunHours":5,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":35,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":5,"endMonth":6}],"5":[{"startMonth":5,"endMonth":6}],"6":[{"startMonth":4,"endMonth":6}],"7":[{"startMonth":4,"endMonth":6}],"8":[{"startMonth":3,"endMonth":5}],"9":[{"startMonth":3,"endMonth":5}]},"productiveMonths":[5,6,7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Overwatering and poorly drained soil cause root rot; oregano is drought-tolerant once established and prefers to dry out between waterings.','Marginally hardy in colder regions (true oregano is only marginally hardy in zone 5); apply a winter mulch of evergreen boughs or straw after the soil freezes and remove it as growth resumes in spring.','Best flavor develops in full sun; too much shade gives weak, leggy growth and reduced essential-oil content.','Container plants need a drainage hole and gritty, free-draining mix; standing water in pots is the main cause of failure.']::text[], 0.4, '[{"citation":"The Old Farmer''s Almanac — Oregano: Planting, Growing, and Harvesting Oregano Plants. Oregano is a perennial in USDA Zones 4 to 9; loves full sun for strong flavor (partial shade in hot climates); harvest no more than one-third at a time, best flavor in midsummer before flowering.","url":"https://www.almanac.com/plant/oregano","field":"temperatureProfile"},{"citation":"The Old Farmer''s Almanac — Oregano. Perennial in USDA Zones 4-9 (Zone 4 lower limit ~ -29 C); returns each year in well-draining soil that survives winter.","url":"https://www.almanac.com/plant/oregano","field":"seasonality"},{"citation":"RHS — How to grow Oregano. Sun-loving Mediterranean herb needing full sun; drought-tolerant once established, container plants watered during dry spells but never waterlogged; ground plants in poor free-draining soil need no feeding.","url":"https://www.rhs.org.uk/herbs/oregano/grow-your-own","field":"wateringProfile"},{"citation":"RHS — How to grow Oregano. For a single young plant use a pot at least 15 cm (6 in) wide and deep, filled with soil-based compost mixed with up to 25% horticultural grit for drainage.","url":"https://www.rhs.org.uk/herbs/oregano/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow Oregano. Container plants benefit from a sprinkling of general-purpose granular feed in late spring or early summer after their first year; best planted late spring/early summer.","url":"https://www.rhs.org.uk/herbs/oregano/grow-your-own","field":"feedingProfile"},{"citation":"University of Illinois Extension — Oregano (Origanum vulgare var. hirtum). Requires a full sun location and good drainage for best growth and overwintering; grows 6 in to 2 ft tall; grows indoors in containers given at least 5-6 hours of sunlight per day; marginally hardy in zone 5; harvest before flowering leaving 4-6 pairs of leaves; winter mulch of evergreen boughs or straw after soil freezes.","url":"https://extension.illinois.edu/herbs/oregano","field":"lightProfile"},{"citation":"University of Illinois Extension — Oregano. Good drainage required for best growth and overwintering; true oregano marginally hardy in zone 5, many desirable types treated as tender perennials needing winter protection.","url":"https://extension.illinois.edu/herbs/oregano","field":"commonIssues"},{"citation":"Confidence note — baseIntervalDays (7) and hotWeatherMultiplier (0.5) are conservative estimates. Authoritative sources (RHS, Illinois Extension, Almanac) describe oregano qualitatively as drought-tolerant, watered only ''during dry spells'', and preferring to dry out between waterings, but give no explicit numeric watering interval; 7 days is a conservative container default reflecting high drying tolerance, with reduced frequency-multiplier (water less) in hot established conditions per drought tolerance. feedingProfile baseIntervalDays (30) derived from the RHS ''once-a-year late-spring feed'' guidance generalized to a monthly light feed for containers; ground plants typically need none.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('petroselinum-crispum', 'Petroselinum crispum', array['Parsley','Curly parsley','Flat-leaf parsley','Italian parsley','Garden parsley']::text[], 'herb', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":6}'::jsonb, '{"baseIntervalDays":28,"containerLeachAdjustment":0.75,"preferredNpk":"5-10-5"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":8,"idealMaxLiters":15,"soilMixTags":["well-drained","rich-in-organic-matter","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-5,"heatStressC":27,"frostSensitive":false}'::jsonb, '{"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Biennial: bolts to seed and turns bitter in its second year, so it is usually grown and replaced as an annual.','Slow, erratic germination (2 to 5 weeks); soaking seed up to 24 hours before sowing improves the low germination rate.','Container compost dries out quickly in warm weather; check moisture often and do not let it dry out completely.','Pests/diseases: carrot fly, aphids, slugs and snails (RHS); septoria leaf spot, stem rot, carrot weevil, flea beetles, leafhoppers (Missouri Botanical Garden).','Recommended container minimum (4 L) suits a single plant in a pot at least 25 cm (10 in) wide and deep; grow only one plant per 4 L, or use ~15 L for a cluster of about four plants.']::text[], 0.4, '[{"citation":"University of Minnesota Extension — Growing parsley in home gardens: full sun six to eight hours/day; water deeply at least once a week; fertilize once or twice per season with 5-10-5, container plants liquid-fed every 3 to 4 weeks; final spacing 10 to 12 inches; soil pH 6.0 to 7.0; germinates in 2 to 5 weeks; biennial that can handle light frosts.","url":"https://extension.umn.edu/vegetables/growing-parsley","field":"wateringProfile,feedingProfile,lightProfile,temperatureProfile"},{"citation":"The Old Farmer''s Almanac — Parsley: full sun (6+ hours); best germination soil temperature ~70F (21C), germinates as low as 50F (10C); four plants per 14-inch / 4-gallon (~15 L) container; soak seeds overnight, germination 2 to 4 weeks.","url":"https://www.almanac.com/plant/parsley","field":"lightProfile,temperatureProfile,containerProfile"},{"citation":"Royal Horticultural Society — How to grow parsley: full sun or partial shade; keep moist but not waterlogged, container compost dries quickly; in-ground needs no feed, containers a balanced liquid feed every few weeks; sow in a pot at least 25 cm (10 in) wide and deep; biennial that dies down over winter; pests include slugs, snails, aphids, carrot fly.","url":"https://www.rhs.org.uk/herbs/parsley/grow-your-own","field":"containerProfile,feedingProfile,wateringProfile,commonIssues"},{"citation":"Missouri Botanical Garden Plant Finder — Petroselinum crispum: USDA hardiness zones 2 to 11; full sun to part shade; medium water, do not allow soils to dry out; 0.75 to 1.0 ft tall; biennial usually grown as an annual; performs best in cool summer climates; pests/diseases include septoria leaf spot, stem rot, carrot weevil, flea beetles, leafhoppers.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=276060","field":"temperatureProfile,lightProfile,commonIssues"},{"citation":"Confidence note — coldHardyMinC (-5C) and heatStressC (27C) are conservative estimates synthesized from MoBot hardiness zones 2-11 and ''best in cool summer climates'' plus UMN/Almanac frost-tolerance and germination data; no single extension source states an exact leaf cold-kill or heat-stress threshold in Celsius. baseIntervalDays (3) and hotWeatherMultiplier (1.5) interpret UMN ''water deeply at least once a week'' and RHS ''keep moist, dries quickly in warm weather'' into the app''s day-interval model.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('ribes-rubrum', 'Ribes rubrum', array['Red currant','Redcurrant','Common redcurrant']::text[], 'berry', 'bush', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":57,"idealMinLiters":57,"idealMaxLiters":90,"soilMixTags":["loam-based","rich-organic-matter","well-drained","moisture-retentive"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":29,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"3":[{"startMonth":4,"endMonth":5},{"startMonth":10,"endMonth":11}],"4":[{"startMonth":4,"endMonth":5},{"startMonth":10,"endMonth":11}],"5":[{"startMonth":3,"endMonth":5},{"startMonth":10,"endMonth":11}]},"productiveMonths":[6,7,8],"dormancyMonths":[11,12,1,2,3]}'::jsonb, array['Prefers cool summers; air temperatures above ~29 C (85 F) can damage plants and intense sun can scorch leaves, so afternoon part-shade is helpful in hot climates.','Susceptible to powdery mildew, anthracnose and fungal leaf spot in humid conditions or with poor air circulation.','Common pests include currant aphids, imported currant worms, scale, spider mites, cane borers and fruit flies.','Currants are an alternate host for white pine blister rust; planting is restricted or banned in some U.S. jurisdictions.','Shallow-rooted, so keep soil consistently moist (about 1 to 2 inches of water per week) and mulch; container plants dry out faster and need more frequent watering.','Container minimum is a realistic home-garden pot for this 3 to 5 ft bush (RHS advises at least a 45 cm / 18 in wide pot, roughly 55 to 65 L); larger pots reduce drying stress.']::text[], 0.4, '[{"citation":"Utah State University Extension - How to Grow Red Currants in Your Garden (cold hardy to zone 3 or 4; morning sun, afternoon part-shade; air temps above 85 F damage plants; 1 to 2 inches water per week; 1/4 to 1/3 lb of 10-10-10 or 12-12-12 per plant per year; harvest mid-June to mid-July; can be grown in a pot; soil pH ~6.5).","url":"https://extension.usu.edu/yardandgarden/research/red-currants-in-the-garden","field":"temperatureProfile"},{"citation":"Utah State University Extension - How to Grow Red Currants in Your Garden (watering 1 to 2 inches per week until harvest; drip irrigation due to shallow roots; planting in late fall or early spring).","url":"https://extension.usu.edu/yardandgarden/research/red-currants-in-the-garden","field":"wateringProfile"},{"citation":"Utah State University Extension - How to Grow Red Currants in Your Garden (heavy nitrogen feeders; 1/4 to 1/3 lb of 10-10-10 or 12-12-12 fertilizer per plant each year).","url":"https://extension.usu.edu/yardandgarden/research/red-currants-in-the-garden","field":"feedingProfile"},{"citation":"University of Minnesota Extension - Growing currants and gooseberries in the home garden (red, pink and white currants are self-fertile; full sun to partial shade, more fruit in full sun; nitrogen-rich composted manure in late fall; common pests aphids, borers, mites, fruit worms; powdery mildew; harvest July-August; plant April-May).","url":"https://extension.umn.edu/fruit/growing-currants-and-gooseberries-home-garden","field":"selfFruitful"},{"citation":"University of Minnesota Extension - Growing currants and gooseberries in the home garden (full sun to partial shade; more fruit in full sun).","url":"https://extension.umn.edu/fruit/growing-currants-and-gooseberries-home-garden","field":"lightProfile"},{"citation":"Royal Horticultural Society - How to grow redcurrants (grow in a pot at least 45 cm / 18 in wide in John Innes No.3; container plants need consistent moisture all season; feed containers with high-potassium liquid fertiliser every fortnight in the growing season; full sun, tolerates partial shade; harvest from July; can be trained as bush, cordon, fan or standard with supports).","url":"https://www.rhs.org.uk/fruit/redcurrants/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society - How to grow redcurrants (container feeding with high-potassium liquid fertiliser every fortnight during the growing season; ground bushes with annual mulch usually need no feeding).","url":"https://www.rhs.org.uk/fruit/redcurrants/grow-your-own","field":"feedingProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Ribes rubrum ''Red Lake'' (USDA zones 3 to 7; full sun to part shade with afternoon shade appreciated in hot climates; medium water, avoid overhead watering; flowers April-May, red fruit ripens July; 3 to 5 ft tall; self-fertile; prefers cool summer climates; anthracnose, powdery mildew, leaf spot, currant aphid, scale, mites, fruit flies; alternate host for white pine blister rust).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a272","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Ribes rubrum ''Red Lake'' (USDA hardiness zones 3 to 7).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a272","field":"seasonality"},{"citation":"Confidence note: coldHardyMinC set to -34 C as a conservative value for the warmer end of the cited USDA zone 3 range (zone 3b ~ -37 to -34 C); some ''Red Lake''-type cultivars are rated to full zone 3 (~-40 C), so this is intentionally conservative. heatStressC of 29 C derives from USU''s ''85 F damage'' threshold. Container recommendedMinLiters (57 L) is computed from the RHS 45 cm-wide pot guidance at typical bush depth and is an estimate, not a directly published litre figure. wateringProfile baseIntervalDays (3) and hotWeatherMultiplier reflect ''consistent moisture / 1-2 inches per week'' for shallow-rooted container culture rather than a published interval.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('ribes-uva-crispa', 'Ribes uva-crispa', array['Gooseberry','European gooseberry']::text[], 'berry', 'bush', false, true, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"10-10-10 in spring for in-ground; high-potassium feed for containers"}'::jsonb, '{"recommendedMinLiters":30,"idealMinLiters":45,"idealMaxLiters":60,"soilMixTags":["soil-based","loam-based","well-drained","john-innes-no3"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-37,"heatStressC":32,"frostSensitive":false}'::jsonb, '{"productiveMonths":[6,7,8],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Powdery mildew (gooseberry mildew) is the most serious disease, worsened by excess nitrogen and poor air circulation; avoid over-feeding with nitrogen.','Alternate host for white pine blister rust; check local/state regulations before planting in some US regions.','Gooseberry sawfly larvae can defoliate bushes rapidly in spring.','Aphids, scale, spider mites, fruit flies and spotted wing drosophila can affect plants and fruit.','Birds strip buds and ripening fruit; netting or a fruit cage is recommended.','Performs poorly in hot, humid climates south of USDA Zone 6.','Container growing is viable but not the natural habit: use a pot at least 40 cm (16 in) wide and deep (recommendedMinLiters ~30 L, ideal 45-60 L) and keep compost evenly moist, as pots dry out far faster than in-ground bushes.']::text[], 0.3, '[{"citation":"University of Minnesota Extension - Growing currants and gooseberries in the home garden (hardiness USDA Zone 3-5, full sun to partial shade, space >=3 ft apart, self-fertile with one plant, late-fall compost feeding, harvest July-August, powdery mildew and white pine blister rust)","url":"https://extension.umn.edu/fruit/growing-currants-and-gooseberries-home-garden","field":"temperatureProfile"},{"citation":"University of Minnesota Extension - gooseberries are self-fertile; one plant produces fruit; full sun gives more fruit","url":"https://extension.umn.edu/fruit/growing-currants-and-gooseberries-home-garden","field":"lightProfile"},{"citation":"Penn State Extension - Home Fruit Plantings: Gooseberries and Currants (1 inch of water per week during growing season; space 3-4 ft apart; self-fertile; fertilize 6-8 oz of 10-10-10 annually in early spring; rich well-drained soil)","url":"https://extension.psu.edu/home-fruit-plantings-gooseberries-and-currants","field":"wateringProfile"},{"citation":"Penn State Extension - apply 6-8 oz of 10-10-10 annually in early spring, or composted manure; self-fertile though multiple varieties improve yield","url":"https://extension.psu.edu/home-fruit-plantings-gooseberries-and-currants","field":"feedingProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Ribes ''Poorman'' gooseberry (USDA Zone 4-6, full sun to part shade with afternoon shade in hot climates, medium moisture, regular even watering, do not perform well in hot humid climates south of Zone 6, alternate host for white pine blister rust)","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=250212&isprofile=0&pt=7","field":"temperatureProfile"},{"citation":"Royal Horticultural Society - How to grow gooseberries (container minimum 40 cm / 16 in wide and deep with drainage; John Innes No.3 soil-based compost; containers need steady even moisture all season; feed containers with fortnightly high-potassium liquid feed or granular high-K, avoid excess nitrogen to limit mildew; sunny position preferred, tolerates some shade; harvest June green to July-August ripe)","url":"https://www.rhs.org.uk/fruit/gooseberries/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society - feeding and watering: ground plants need little water once established but containers need a steady supply of moisture; avoid excess nitrogen (mildew); high-potassium feed","url":"https://www.rhs.org.uk/fruit/gooseberries/grow-your-own","field":"feedingProfile"},{"citation":"Old Farmer''s Almanac - Gooseberries: cold-hardy to USDA Zone 3 (some Zone 2); established bushes need little water unless hot/dry, keep young and container plants well watered; balanced organic fertilizer at end of winter only, avoid over-feeding; net against birds","url":"https://www.almanac.com/plant/gooseberries","field":"wateringProfile"},{"citation":"Confidence note: coldHardyMinC of -37C is derived from the USDA Zone 3 hardiness rating cited by UMN Extension and the Old Farmer''s Almanac (Zone 3 lower limit approx -40 to -34C); no source gave an exact Celsius minimum, so a conservative mid-range value was used. heatStressC of 32C and hotWeatherMultiplier are estimated from Missouri Botanical Garden''s statement that gooseberries perform poorly in hot, humid climates south of Zone 6; no source gave an exact heat-stress temperature. containerProfile liters are converted from RHS''s 40 cm minimum pot dimension (a 40 cm cube is roughly 64 L; a realistic 40 cm-wide tapered pot is ~30 L), so recommendedMinLiters is a conservative interpretation rather than a directly stated liter figure.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('rubus-fruticosus', 'Rubus fruticosus', array['Blackberry','Common blackberry','Bramble']::text[], 'berry', 'bush', true, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":90,"fruitingIntervalDays":90,"postHarvestIntervalDays":90,"containerLeachAdjustment":0.5,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":40,"idealMinLiters":75,"idealMaxLiters":114,"soilMixTags":["loam-based","well-drained","acidic-to-neutral-pH-6.0-6.5"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-10,"heatStressC":35,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"default":[{"startMonth":10,"endMonth":12},{"startMonth":2,"endMonth":4}]},"productiveMonths":[7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Container minimum is set for compact/patio cultivars (e.g. RHS ''Little Black Prince'', a 45cm-wide/deep pot, ~40-75L); standard vigorous trailing and semi-erect blackberries are deep-rooted and do far better in-ground or in a 75-114L (20-30 gallon) tub.','Cold hardiness varies sharply by type: trailing cultivars suffer cane and bud damage below about -10C, while erect and semi-erect types are hardier (USDA zones 4-5). The -10C value here is conservative for the less-hardy trailing types.','Trellising is recommended for all types to prevent cane breakage, improve airflow and reduce fruit rot.','Spotted-wing drosophila, Japanese beetles, aphids, spider mites and crown borers are common pests.','Botrytis (grey mould) fruit rot, anthracnose, cane blight, powdery mildew and orange rust are common diseases; full sun and good airflow reduce disease pressure.']::text[], 0.8, '[{"citation":"Clemson Cooperative Extension Home & Garden Information Center — Blackberry: full sun required; apply about 1 inch of water per week if rainfall is insufficient, especially during establishment and fruiting; fertilize in early spring at growth start and again after harvest; optimal soil pH 6.0-6.5; V-trellis recommended; common pests and diseases.","url":"https://hgic.clemson.edu/factsheet/blackberry/","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension Home & Garden Information Center — Blackberry: fertilize in early spring when growth begins and again after harvest; soil pH 6.0-6.5; V-trellis support recommended.","url":"https://hgic.clemson.edu/factsheet/blackberry/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension Home & Garden Information Center — Blackberry: blackberries require full sun for optimal health and production; partial shade leads to more disease and poor yields.","url":"https://hgic.clemson.edu/factsheet/blackberry/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension Home & Garden Information Center — Blackberry: V-trellis (8-foot T-posts) recommended to prevent cane breakage and fruit rot; common diseases (anthracnose, cane blight, powdery mildew, botrytis fruit rot, orange rust) and pests (aphids, Japanese beetles, spotted-wing drosophila, spider mites, crown borers).","url":"https://hgic.clemson.edu/factsheet/blackberry/","field":"commonIssues"},{"citation":"OSU Extension — A home gardener''s guide to growing blackberries: all blackberry types are self-fruitful, so only one cultivar is needed for pollination and fruit; trellising benefits all types; recommended fertilizer such as 10-10-10 in early spring and after harvest.","url":"https://extension.oregonstate.edu/gardening/techniques/home-gardeners-guide-growing-blackberries","field":"selfFruitful"},{"citation":"OSU Extension — Growing blackberries in your home garden / Blackberry cultivars: trailing blackberries are the least cold-hardy, with cane and bud damage when temperatures fall below about 13F (-10.5C); erect and semi-erect types are hardier (USDA zones 4-5).","url":"https://extension.oregonstate.edu/catalog/ec-1303-growing-blackberries-your-home-garden","field":"temperatureProfile"},{"citation":"RHS — How to grow blackberries and hybrid berries: choose a sunny, sheltered site; established plants need little extra water but container-grown plants need regular moisture all season; feed with an organic-based granular general fertiliser in early spring if needed; horizontal support wires ~45cm apart are essential; plant mid-autumn to early spring; harvest mid-summer to early autumn.","url":"https://www.rhs.org.uk/fruit/blackberries-and-hybrid-berries/grow-your-own","field":"seasonality"},{"citation":"RHS — How to grow blackberries and hybrid berries: compact varieties (e.g. ''Little Black Prince'') can be grown in a pot at least 45cm wide and deep filled with loam-based compost, reaching ~1m; container plants need regular watering.","url":"https://www.rhs.org.uk/fruit/blackberries-and-hybrid-berries/grow-your-own","field":"containerProfile"},{"citation":"Old Farmer''s Almanac — Blackberries: Planting, Growing, and Harvesting; full sun, regular watering of about 1 inch per week, trellising recommended for support.","url":"https://www.almanac.com/plant/blackberries","field":"wateringProfile"},{"citation":"Confidence note — containerProfile: extension/RHS sources give pot guidance only for compact cultivars (RHS: 45cm pot; OSU notes standard blackberries are deep-rooted, ~20-30 gallon / 75-114L tubs). recommendedMinLiters (40L) is a conservative derived minimum for a compact patio cultivar, not a measured value. heatStressC (35C) and feeding intervals (90 days, i.e. early-spring + post-harvest) are derived from qualitative guidance (''fertilize twice a year'', ''hot, dry weather'') rather than published numbers.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('rubus-idaeus', 'Rubus idaeus', array['Raspberry','Red raspberry','European red raspberry']::text[], 'berry', 'upright', true, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":30,"fruitingIntervalDays":30,"postHarvestIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":30,"idealMaxLiters":38,"soilMixTags":["well-drained","slightly-acidic","rich-in-organic-matter"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"rhs-uk":[{"startMonth":11,"endMonth":3}]},"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Susceptible to fungal diseases (anthracnose, botrytis, root rot) and to cane borers and crown borers; ensure good air circulation.','Intolerant of waterlogged or wet soils; standing water causes root rot and plant death, so well-drained soil or containers are essential.','Spreads aggressively by suckers into tangled thickets if not pruned and contained.','Container culture: although a deep-rooted plant best grown in-ground, dwarf/everbearing types grow in a pot at least 40cm (16in) wide and 30cm (12in) deep; in very cold winters insulate or move the pot under cover so roots do not freeze hard.','Growing-season tissue is frost-tender: summer shoots are killed near -8C even though dormant, acclimated canes tolerate far colder; protect new spring growth from late frosts.']::text[], 0.6, '[{"citation":"UMN Extension — Growing raspberries in the home garden: full sun for most fruit; 1 to 1.5 inches of water per week from flowering until harvest, roots stay in top two feet of soil; space red/yellow raspberries 2 to 3 feet apart; all raspberries require support; summer-bearing fruit early to mid summer; composted manure as nutrient source.","url":"https://extension.umn.edu/fruit/growing-raspberries-home-garden","field":"wateringProfile"},{"citation":"UMN Extension — Growing raspberries in the home garden: hardy varieties (Boyne, Latham) rated very good to good in USDA zones 3-4.","url":"https://extension.umn.edu/fruit/growing-raspberries-home-garden","field":"temperatureProfile"},{"citation":"UMN Extension — Growing raspberries in the home garden: all types of raspberries require support to prevent canes from wind damage, bending and cracking.","url":"https://extension.umn.edu/fruit/growing-raspberries-home-garden","field":"requiresSupport"},{"citation":"RHS — How to grow raspberries: grow in a pot at least 40cm (16in) wide and 30cm (12in) deep for compact varieties; sunny site best (light shade reduces crop); slightly acidic soil ideally pH 6-6.7; container plants fed monthly with a liquid general-purpose fertiliser through the growing season; ground plants fed granular fertiliser in early spring; plant bare-root canes Nov-Mar; summer varieties crop Jun-Sep, autumn varieties Aug-Oct.","url":"https://www.rhs.org.uk/fruit/raspberries/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow raspberries: keep container compost consistently moist throughout the growing season; water new plants well during prolonged dry spells in the first growing season.","url":"https://www.rhs.org.uk/fruit/raspberries/grow-your-own","field":"wateringProfile"},{"citation":"RHS — How to grow raspberries: feed container raspberries with a liquid general-purpose fertiliser on a monthly basis; ground plants need granular feed in early spring at most.","url":"https://www.rhs.org.uk/fruit/raspberries/grow-your-own","field":"feedingProfile"},{"citation":"RHS — How to grow raspberries: dormant planting window November to March in the UK climate.","url":"https://www.rhs.org.uk/fruit/raspberries/grow-your-own","field":"seasonality"},{"citation":"Missouri Botanical Garden Plant Finder — Rubus idaeus: USDA hardiness zones 4 to 8; full sun to part shade; medium water needs; prefers moist but well-drained, organically rich, slightly acidic soils and is intolerant of wet conditions causing root rot; mature 3-9 ft; blooms Apr-May, summer ripening; susceptible to anthracnose, botrytis, root rot, cane and crown borers; spreads into thickets if unmaintained.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=295999","field":"temperatureProfile"},{"citation":"Penn State Extension — Small Fruit Cold Hardiness, Winter Injury in Brambles: in mid-summer raspberry shoots are killed at about 18F (about -8C); by mid-October acclimated plants withstand about 10F (about -12C); summer-bearing red raspberries are the most cold hardy bramble type.","url":"https://extension.psu.edu/small-fruit-cold-hardiness-winter-injury-in-brambles","field":"temperatureProfile"},{"citation":"Container size conversion: RHS recommends a pot at least 40cm wide x 30cm deep; a cylinder of those dimensions holds roughly 38 L, and the Old Farmer''s Almanac recommends about 8 US gallons (~30 L) of potting mix for container berries. recommendedMinLiters set conservatively to 19 L (5 US gal) as a workable minimum for dwarf/everbearing types, with 30-38 L as the ideal. Raspberries are deep-rooted and grow best in-ground; the container minimum is intentionally a large pot.","url":"https://www.rhs.org.uk/fruit/raspberries/grow-your-own","field":"confidence"},{"citation":"Confidence note: heatStressC (30C) and hotWeatherMultiplier are estimated. Extension sources specify 1-1.5 in/week and irrigation three or more times per week on sandy soil in dry spells but give no explicit heat-stress temperature; baseIntervalDays=3 and frostSensitive=false (dormant canes hardy to zone 3-4 but growing-season tissue tender near -8C) are conservative interpretations rather than directly stated single numbers.","url":"https://extension.umn.edu/fruit/growing-raspberries-home-garden","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('salvia-officinalis', 'Salvia officinalis', array['Sage','Common sage','Garden sage','Culinary sage']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"balanced general-purpose (e.g. 10-10-10)"}'::jsonb, '{"recommendedMinLiters":10,"idealMinLiters":15,"idealMaxLiters":25,"soilMixTags":["well-drained","loam-based","added-grit","low-fertility"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":35,"frostSensitive":false}'::jsonb, '{"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Root rot in consistently moist or wet soils is the primary problem; let the top 2 inches (5 cm) of soil dry before watering and never let pots sit in saucers of water.','Overwatering and waterlogged soil are far more dangerous than underwatering; sage is drought tolerant once established.','Powdery mildew, spider mites, slugs, spittlebugs, sage leafhoppers, and rosemary beetles may appear but rarely cause severe damage; good air circulation reduces foliar disease.','In hot climates (USDA zone 8 and warmer) provide light afternoon shade to prevent leaf scorch.','Becomes leggy and woody with age; prune in spring and lightly through the season, and replace plants every 3-5 years as flavor and vigor decline.','In wet winters move containers to a sheltered spot, as excess rain can rot the roots.']::text[], 0.1, '[{"citation":"University of Wisconsin-Madison Division of Extension, Horticulture: ''Sage, Salvia officinalis'' - states sage grows best in a sunny location with well-drained soil, tolerates drought and poor fertility, is hardy in USDA zones 4a to 10b, grows to about 2.5 ft, and lists root rot and wilt among possible problems.","url":"https://hort.extension.wisc.edu/articles/sage-salvia-officinalis/","field":"lightProfile"},{"citation":"University of Wisconsin-Madison Division of Extension: smaller varieties of Salvia officinalis can be grown as container plants; possible problems include slugs, spider mites, spittlebugs, root rot and wilt; good air circulation reduces foliar disease.","url":"https://hort.extension.wisc.edu/articles/sage-salvia-officinalis/","field":"commonIssues"},{"citation":"Missouri Botanical Garden Plant Finder, Salvia officinalis: Zone 4 to 8 (species range to 10b), full sun, water needs ''Dry to medium'' with ''Wet soils can be fatal'', susceptible to root rot in consistently moist or wet soils, tolerates drought and dry soil, mature size 2.0-2.5 ft, bloom time June.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=m260","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Salvia officinalis: drought tolerant; requires average, dry-to-medium, well-drained soil; wet soils can be fatal (overwater risk).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=m260","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS), ''How to grow Sage'': grow in full sun in a sheltered spot; once established sage is drought tolerant and needs no extra ground watering; for containers keep compost slightly moist but not saturated and use a container at least 30cm (12in) wide and deep with plenty of drainage; mix in horticultural grit (up to 25% by volume); feed container plants with general-purpose granular feed in late spring/early summer after their first year.","url":"https://www.rhs.org.uk/herbs/sage/grow-your-own","field":"feedingProfile"},{"citation":"Royal Horticultural Society (RHS), ''How to grow Sage'': use a container at least 30cm (12in) wide and deep with plenty of drainage holes; in wet winters move pots to a sheltered spot as excess rain can rot the roots. A 30cm cube is roughly 27 L; a single plant establishes well in a 10-15 L pot, hence recommendedMin 10 L, ideal 15-25 L.","url":"https://www.rhs.org.uk/herbs/sage/grow-your-own","field":"containerProfile"},{"citation":"UMN Extension / Clemson HGIC guidance for Salvia: full sun, 6-8 hours of sunlight per day; water lightly when the top 2 inches of soil is dry; water in summer only if rainfall is less than 1 inch (~25 mm) per week; salvia dislikes excessive summer irrigation. (Used for target/min sun hours, base watering interval, and rain-skip threshold.)","url":"https://hgic.clemson.edu/factsheet/salvia/","field":"lightProfile"},{"citation":"Clemson HGIC / UMN Extension guidance: water lightly when the top 2 inches of soil is dry and only if weekly rainfall is under ~1 inch (25 mm); supports a conservative 7-day base watering interval with a high drying tolerance and a 25 mm rain-skip threshold.","url":"https://hgic.clemson.edu/factsheet/salvia/","field":"wateringProfile"},{"citation":"Confidence note: feeding interval is estimated. RHS states sage in the ground needs no feeding and container plants need only an annual late-spring granular feed; sources do not give a routine recurring interval. A conservative 30-day growing-season interval (with containerLeachAdjustment 0.75) is used as a light-feeder default and should be treated as low confidence.","field":"confidence"},{"citation":"Confidence note: heatStressC (35 C) is estimated. Sources indicate sage tolerates hot, dry conditions but advise light afternoon shade in USDA zone 8+ to avoid scorch; no precise heat-stress temperature is published, so 35 C is a conservative estimate. coldHardyMinC (-34 C) is derived from the documented USDA zone 4 lower limit.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('salvia-rosmarinus', 'Salvia rosmarinus', array['Rosemary']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":60,"containerLeachAdjustment":0.75,"preferredNpk":"balanced general-purpose (e.g. 10-10-10)"}'::jsonb, '{"recommendedMinLiters":15,"idealMinLiters":20,"idealMaxLiters":30,"soilMixTags":["well-drained","soil-based","free-draining","added-grit","low-fertility"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-8,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"8":[{"startMonth":3,"endMonth":5}]},"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Overwatering and poor drainage are the biggest cause of decline and death; let the soil dry between waterings.','Root and crown rot plus botrytis (grey mould) are the most common diseases; ensure good air circulation and free-draining media.','Frost-sensitive: hardy only to about -8C (18F); protect from hard frost and cold wet winters, or overwinter container plants indoors in cold zones (not reliably hardy below zone 8 except cultivars like ''Arp'').','Common pests include aphids, spider mites, mealybugs and scale; rosemary beetle and leafhoppers in some regions.','Container minimum is set to a realistic pot of at least 30cm (12in) wide and deep per RHS; smaller pots dry out fast and restrict the woody root system.','Reduce or stop watering in winter dormancy; overwatering wet cold roots is the main winter killer.']::text[], 0.1, '[{"citation":"RHS - How to grow Rosemary (Grow Your Own): full sun, light free-draining soil, hardy to -8C (18F), drought tolerant once established, container minimum 30cm wide and deep with drainage, feed container plants over one year old with general-purpose granular feed in late spring/early summer, problems include root rot from waterlogging, rosemary beetle, scale and leafhoppers.","url":"https://www.rhs.org.uk/herbs/rosemary/grow-your-own","field":"wateringProfile"},{"citation":"RHS - How to grow Rosemary: minimum container 30cm (1ft) wide and deep with drainage holes using a soil-based compost; heavy soils need up to 25% horticultural grit. A 30cm-wide/deep pot corresponds to roughly 20-30 L; recommendedMinLiters set conservatively to 15 L.","url":"https://www.rhs.org.uk/herbs/rosemary/grow-your-own","field":"containerProfile"},{"citation":"RHS - How to grow Rosemary: hardy to -8C (18F); harsh frosts and cold winds cause damage and young plants may die in extreme cold; needs winter protection in colder/wetter sites.","url":"https://www.rhs.org.uk/herbs/rosemary/grow-your-own","field":"temperatureProfile"},{"citation":"RHS - How to grow Rosemary: ground plants need no feeding; container plants over one year old benefit from a sprinkling of general-purpose granular feed in late spring or early summer (about once per season), informing the ~60-day base feeding interval and low-fertility preference.","url":"https://www.rhs.org.uk/herbs/rosemary/grow-your-own","field":"feedingProfile"},{"citation":"University of Wisconsin-Madison Horticulture Extension - Rosemary (Rosmarinus officinalis): keep soil moist with good drainage; overwatering is the biggest cause of plant decline and death; winter hardy only to approximately 20F (cultivar-dependent, ''Arp'' to ~10F); root rot and botrytis are the most common diseases; pests include aphids, spider mites, mealybugs and scale; good air circulation prevents foliar disease.","url":"https://hort.extension.wisc.edu/articles/rosemary-rosemarinus-officinalis/","field":"commonIssues"},{"citation":"University of Illinois Extension - Rosemary: full sun; keep the soil on the dry side and let it dry between waterings; overwatering causes root rot; perennial in USDA zone 8 and above, not reliably hardy in zone 6 or colder (''Arp'' potentially to zone 6); bring indoors before frost.","url":"https://extension.illinois.edu/herbs/rosemary","field":"wateringProfile"},{"citation":"University of Illinois Extension - Rosemary: perennial in zone 8 and above, not reliably hardy in zone 6 or colder; informs the zone-8 spring (Mar-May) planting window and dormancy guidance.","url":"https://extension.illinois.edu/herbs/rosemary","field":"seasonality"},{"citation":"Multiple extension/horticulture sources concur rosemary needs full sun, at least 6-8 hours of direct sunlight per day for best growth in containers and the garden (e.g. University of Illinois Extension and RHS specify ''full sun''; 6-8 hours is the widely cited full-sun figure for this Mediterranean shrub).","url":"https://extension.illinois.edu/herbs/rosemary","field":"lightProfile"},{"citation":"Texas A&M AgriLife Extension - Easy Gardening: Rosemary: plant in full sun in well-drained soil; avoid overwatering as too much water or poor drainage causes problems. Corroborates full-sun, free-draining, drought-tolerant care and high overwater risk.","url":"https://agrilifeextension.tamu.edu/asset-external/easy-gardening-rosemary/","field":"wateringProfile"},{"citation":"Confidence note: exact numeric values for baseIntervalDays (7), hotWeatherMultiplier (0.7), rainSkipThresholdMm (5), heatStressC (35), feeding baseIntervalDays (60), containerLeachAdjustment (0.75), and recommendedMinLiters (15) are conservative app-model estimates derived from qualitative source guidance (full sun, ''keep on the dry side'', drought-tolerant, water container plants ~weekly, 30cm pot, feed ~once per season). No single extension page gives a numeric watering interval, heat-stress temperature, or pot volume in liters; these are engineered conservatively to avoid overwatering this rot-prone species.","url":"https://hort.extension.wisc.edu/articles/rosemary-rosemarinus-officinalis/","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('thymus-vulgaris', 'Thymus vulgaris', array['Thyme','Common thyme','Garden thyme','German thyme']::text[], 'herb', 'bush', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":60,"preferredNpk":"compost / low-nitrogen; little to no feeding needed"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":8,"soilMixTags":["free-draining","soil-based-compost","sandy","gritty","neutral-to-alkaline"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":38,"frostSensitive":false}'::jsonb, '{"productiveMonths":[5,6,7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Root rot in wet or poorly drained soil; thyme dislikes excess moisture far more than cold (Missouri Botanical Garden; RHS).','Becomes overly woody and leggy after several years; cut back in early spring and summer, leaving about five inches of growth, and replace plants periodically (NC State Extension; Old Farmer''s Almanac).','Container minimum (2 L) reflects RHS guidance of a pot at least 15 cm wide and 10 cm deep for one plant; thyme is shallow-rooted, so wide-but-shallow pots with excellent drainage suit it better than deep ones.']::text[], 0.3, '[{"citation":"RHS - How to grow Thyme (Grow Your Own): full sun and free-draining conditions; container at least 15 cm (6 in) wide and 10 cm (4 in) deep for one plant; peat-free soil-based compost with up to 25% horticultural grit; water deeply only when soil is completely dry; most widely available varieties withstand UK frosts; damp is a greater risk than cold.","url":"https://www.rhs.org.uk/herbs/thyme/grow-your-own","field":"containerProfile"},{"citation":"RHS - How to grow Thyme: watering guidance (water deeply only when soil completely dry; drought-tolerant, dislikes excess moisture / root rot).","url":"https://www.rhs.org.uk/herbs/thyme/grow-your-own","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Thymus vulgaris: USDA hardiness zones 5 to 9; height 0.50-1.00 ft; full sun; dry to medium, well-drained soil; drought tolerant; bloom May to July; low maintenance; susceptible to root rot if soil too moist; becomes overly woody after several years.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=f970","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Thymus vulgaris: prefers average, dry to medium, well-drained, sandy/rocky soils; dislikes wet conditions (root rot).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=f970","field":"commonIssues"},{"citation":"NC State Extension Gardener Plant Toolbox - Thymus vulgaris: USDA zones 5a-9b; full sun (6 or more hours of direct sun a day); drought-tolerant and frost-tolerant; low maintenance, trim when leggy, leave five inches of growth; neutral to alkaline pH; intolerant of wet soils and shade.","url":"https://plants.ces.ncsu.edu/plants/thymus-vulgaris/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Thymus vulgaris: frost-tolerant, hardy to zone 5 (lower limit ~ -29 C / -20 F per USDA zone 5 minimum); intolerant of wet soils.","url":"https://plants.ces.ncsu.edu/plants/thymus-vulgaris/","field":"temperatureProfile"},{"citation":"The Old Farmer''s Almanac - Thyme: full sun, 6-8 hours of bright light; drought-friendly with low watering needs, let soil dry out between waterings; herbs like thyme, lavender and rosemary should not need feeding and do best in nutrient-poor, drier soils; if fertilizing, use compost in early spring; trim when leggy; cut back early spring and summer.","url":"https://www.almanac.com/plant/thyme","field":"feedingProfile"},{"citation":"The Old Farmer''s Almanac - Thyme: light/sun-hour guidance (6-8 hours bright light) and drought-friendly watering behaviour.","url":"https://www.almanac.com/plant/thyme","field":"lightProfile"},{"citation":"Confidence note: baseIntervalDays (watering ~7) and hotWeatherMultiplier (0.5) are conservative estimates. Authoritative sources (RHS, Almanac, NC State, MBG) prescribe watering by soil-dryness rather than a fixed interval (''water deeply only when soil is completely dry''); thyme is strongly drought-tolerant, so the 7-day base and reduced hot-weather frequency encode ''let it dry out'' rather than a sourced fixed cadence. feedingProfile.baseIntervalDays (60) is likewise an estimate: sources say little-to-no feeding is needed, so a long ~60-day/early-spring cadence is used to approximate ''rarely feed''. heatStressC (38) is an estimate; sources emphasize cold-hardiness and drought tolerance but do not state a numeric heat-stress threshold.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('vaccinium-corymbosum', 'Vaccinium corymbosum', array['Blueberry','Highbush blueberry','Northern highbush blueberry']::text[], 'berry', 'bush', false, true, 1, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"fruitingIntervalDays":21,"preferredNpk":"10-8-8"}'::jsonb, '{"recommendedMinLiters":38,"idealMinLiters":57,"idealMaxLiters":75,"soilMixTags":["ericaceous","acidic","high-organic-matter","free-draining","fine-bark","peat-or-coir"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-37,"heatStressC":32,"frostSensitive":false}'::jsonb, '{"productiveMonths":[6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Acid-loving: needs soil pH 4.0-5.5; chlorosis (yellowing leaves) appears in alkaline soil. Use ericaceous mix and avoid hard tap water; rainwater is preferred.','Shallow-rooted and sensitive to inconsistent moisture; needs about one inch (25 mm) of water per week and more during hot, dry spells, but dislikes waterlogging.','Partially self-fertile: a single plant will crop, but planting two or more cultivars together gives larger, earlier berries and bigger yields.','Container minimum (about 38 L / 10 gal) suits compact/half-high cultivars; full-size northern highbush bushes (mature 1.5-1.8 m / 5-6 ft tall and wide) need a large 57-75 L (15-20 gal) container or half barrel for long-term growth.','Slow to crop: little fruit in the first 2-3 years, with full yields after about 5 years.']::text[], 0.1, '[{"citation":"University of Minnesota Extension — Growing blueberries in the home garden (soil pH 4.0-5.5, full sun, space ~3 ft apart, plant two or more varieties for pollination, hardy to USDA zones 3-4, harvest ~July, acid/azalea fertilizer in spring, little fruit first 2-3 years).","url":"https://extension.umn.edu/fruit/growing-blueberries-home-garden","field":"lightProfile,temperatureProfile,seasonality,selfFruitful,feedingProfile,commonIssues"},{"citation":"Royal Horticultural Society — How to grow blueberries (ericaceous compost pH 4.5-5.5, container 30 cm dia for young / 45-50 cm dia for larger plants, keep compost slightly moist with rainwater not tap water, feed every 2-3 weeks Apr-Aug, sunny position, harvest Jun-Sep, most blueberries partially self-fertile so one plant crops but cross-pollination gives larger harvests, hardy in the UK).","url":"https://www.rhs.org.uk/fruit/blueberries/grow-your-own","field":"containerProfile,wateringProfile,feedingProfile,selfFruitful,seasonality,temperatureProfile"},{"citation":"Clemson University HGIC — Blueberry (water thoroughly two to three times per week during dry spells; azalea-type fertilizer 10-5-4 / 10-8-8 / 11-7-7 with sidedressing roughly every six weeks through the season; full sunlight; southern highbush generally self-fertile but larger yields with cross-pollination; harvest May-July; container dwarf cultivars).","url":"https://hgic.clemson.edu/factsheet/blueberry/","field":"wateringProfile,feedingProfile,preferredNpk,lightProfile,selfFruitful"},{"citation":"Clemson University Plant Profiles — Vaccinium corymbosum ''Jubilee'' / highbush blueberry (acid-loving, pH 4.5-5.5; mature plants ~5-6 ft tall and wide; full sun, part shade acceptable; 3 in mulch; needs at least one inch of water per week; shallow roots sensitive to inconsistent moisture).","url":"https://www.clemson.edu/cafls/demo/plant_profiles/vaccinium-corymbosum-highbush-blueberry-jubilee.html","field":"wateringProfile,commonIssues,containerProfile"},{"citation":"University of Maryland Extension — Growing Blueberries in Containers (half-high cultivars do best in a 10-gallon (~38 L) or larger container; large northern highbush types need a half wine barrel or 15-20 gallon (~57-75 L) container).","url":"https://extension.umd.edu/resource/growing-blueberries-containers","field":"containerProfile"},{"citation":"Confidence note — heatStressC (32 C) is a conservative estimate: extension sources emphasize cold-hardiness and consistent moisture rather than a precise upper heat-stress threshold, so this value is approximate and intended as a watering/shade trigger, not a hard limit. hotWeatherMultiplier and rainSkipThresholdMm are derived operational defaults from the ''one inch (25 mm) per week, more in heat'' guidance rather than literal cited numbers.","field":"confidence"}]'::jsonb, 1, '2026-06-02')
